import json
from angular import directive

@directive('dataGrid')
class DataGrid:
    def __init__(self, json_string):
        self.settings = self.parse_json(json_string)
        self.data = self.settings.get('data', [])
        self.columns = self.settings.get('columns', [])
        self.sort_column = None
        self.sort_order = 'asc'
        self.search_query = ''

    def parse_json(self, json_string):
        try:
            return json.loads(json_string)
        except json.JSONDecodeError:
            return {}

    def sort_data(self):
        if self.sort_column:
            self.data.sort(key=lambda x: x[self.sort_column], reverse=(self.sort_order == 'desc'))

    def search_data(self):
        if self.search_query:
            return [row for row in self.data if self.search_query.lower() in str(row).lower()]
        return self.data

    def set_sort(self, column):
        if self.sort_column == column:
            self.sort_order = 'desc' if self.sort_order == 'asc' else 'asc'
        else:
            self.sort_column = column
            self.sort_order = 'asc'
        self.sort_data()

    def set_search_query(self, query):
        self.search_query = query
        self.search_data()

    def get_display_data(self):
        return self.search_data()
